<?php

declare(strict_types=1);

namespace App\Services;

use App\Core\Database;

/**
 * Imports the researched, public-source business list (database/seeds/
 * national_import.json, generated by tools/extract-canvas.js) into the live
 * schema as clearly-marked **unclaimed** directory listings, creating any
 * missing states, regions and towns along the way.
 *
 * Fully idempotent: providers are keyed on their slug, locations on their
 * (state, slug), and join rows use INSERT IGNORE / existence checks, so running
 * it again only fills gaps. Listings are flagged is_unclaimed = 1 / is_verified
 * = 0 and only expose contact details the business already publishes.
 */
final class NationalImportSeeder
{
    /** @var array<string,array<string,array<string,mixed>>> state abbr => town name => {pc,lat,lng} */
    private array $townDetails = [];

    /**
     * Trade bucket => the service that is a DIRECT match for that trade (the
     * business's headline service).
     */
